import sys

class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def __init__(self):
        self.head = None

    def push(self, x: int) -> None:
        node = ListNode(x)
        node.next = self.head
        self.head = node

    def pop(self) -> int:
        if self.isEmpty():
            return -1
        val = self.head.val
        self.head = self.head.next
        return val

    def top(self) -> int:
        if self.isEmpty():
            return -1
        return self.head.val

    def isEmpty(self) -> bool:
        return self.head is None

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
