#include <numeric>

#include <iostream>
#include <string>

using namespace std;

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* head;
    Solution() : head(nullptr) {}

    void push(int x) {
        ListNode* node = new ListNode(x);
        node->next = head;
        head = node;
    }

    int pop() {
        if (isEmpty()) return -1;
        int val = head->val;
        ListNode* temp = head;
        head = head->next;
        delete temp;
        return val;
    }

    int top() {
        if (isEmpty()) return -1;
        return head->val;
    }

    bool isEmpty() {
        return head == nullptr;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    for (int i = 0; i < n; i++) {
        string op;
        if (!(cin >> op)) return 0;
        if (op == "push") {
            int x;
            if (!(cin >> x)) return 0;
            sol.push(x);
        } else if (op == "pop") {
            cout << sol.pop() << endl;
        } else if (op == "top") {
            cout << sol.top() << endl;
        } else if (op == "isEmpty") {
            cout << (sol.isEmpty() ? "true" : "false") << endl;
        }
    }
    return 0;
}
